 81→    private fun initPreviewProgress() {
 82→        mProgressSeekBar = findViewById(R.id.preview_progress_seek_bar)
 83→        mProgressText = findViewById(R.id.preview_progress_text)
 84→        val progressLayout = findViewById<LinearLayout>(R.id.preview_progress_layout)
 85→
 86→        // Show layout only when the cardList is bigger than 1
 87→        if (mCardList.size > 1) {
 88→            progressLayout.visibility = View.VISIBLE
 89→            mProgressSeekBar.max = mCardList.size - 1
 90→            setSeekBarListener()
 91→            updateProgress()
