 97→            override fun onProgressChanged(seekBar: SeekBar, progress: Int, fromUser: Boolean) {
 98→                if (fromUser) {
 99→                    mIndex = progress
100→                    updateProgress()
101→                    currentCard = getColUnsafe.getCard(mCardList[mIndex])
102→                    displayCardQuestion()
103→                }
104→            }
105→
106→            override fun onStartTrackingTouch(seekBar: SeekBar) {
107→                // Mandatory override, but unused
108→            }
109→
110→            override fun onStopTrackingTouch(seekBar: SeekBar) {
111→                if (mIndex >= 0 && mIndex < mCardList.size) {
112→                    currentCard = getColUnsafe.getCard(mCardList[mIndex])
113→                    displayCardQuestion()
