278→    private fun setCurrentCardFromNoteEditorBundle(col: Collection): Card? {
279→        assert(mNoteEditorBundle != null)
280→        currentCard = getDummyCard(mEditedNotetype, cardIndex, getBundleEditFields(mNoteEditorBundle))
281→        // example: a basic card with no fields provided
282→        if (currentCard == null) {
283→            return null
284→        }
285→        val newDid = mNoteEditorBundle!!.getLong("did")
286→        if (col.decks.isDyn(newDid)) {
287→            currentCard!!.oDid = currentCard!!.did
288→        }
289→        currentCard!!.did = newDid
290→        val currentNote = currentCard!!.note()
291→        val tagsList = mNoteEditorBundle!!.getStringArrayList("tags")
292→        setTags(currentNote, tagsList)
293→        return currentCard
294→    }
