296→    /**
297→     * Set the set tags of currentNote to tagsList.  We make no
298→     * assumption on the content of tagsList, except that its strings
299→     * are valid tags (i.e. no spaces in it).
300→     */
301→    private fun setTags(currentNote: Note, tagsList: List<String>?) {
302→        val currentTags = currentNote.tags.toTypedArray()
303→        for (tag in currentTags) {
304→            currentNote.delTag(tag)
305→        }
306→        if (tagsList != null) {
307→            val tagsSet = currentNote.col.tags.canonify(tagsList)
308→            currentNote.addTags(tagsSet)
309→        }
310→    }
