334→    private fun indexFromOrdinal(col: Collection, ordinal: Int, fieldValues: MutableList<String>): Int {
335→        val notetype = mEditedNotetype ?: return 0
336→        return if (notetype.isCloze) {
337→            val note = col.newNote(notetype)
338→            for (i in 0 until fieldValues.size.coerceAtMost(note.fields.size)) {
339→                note.setField(i, fieldValues[i])
340→            }
341→            val clozeNumbers = col.clozeNumbersInNote(note)
342→            val index = clozeNumbers.indexOf(ordinal + 1)
343→            if (index != -1) index else 0
344→        } else {
345→            ordinal
346→        }
347→    }
