350→    /**
351→     * This method generates a note from a sample model, or fails if invalid
352→     * @param index The index in the templates for the model. NOT `ord`
353→     */
354→    fun getDummyCard(notetype: NotetypeJson, index: Int): Card? {
355→        return getDummyCard(notetype, index, notetype.fieldsNames.toMutableList())
356→    }
