358→    /**
359→     * This method generates a note from a sample model, or fails if invalid
360→     * @param cardIndex The index in the templates for the model. NOT `ord`
361→     */
362→    private fun getDummyCard(notetype: NotetypeJson?, cardIndex: Int, fieldValues: MutableList<String>): Card? {
363→        Timber.d("getDummyCard() Creating dummy note for index %s", cardIndex)
364→        if (notetype == null) {
365→            return null
366→        }
367→        if (mAllFieldsNull) {
368→            getLabels(fieldValues)
369→        }
370→        val n = getColUnsafe.newNote(notetype)
371→        var i = 0
372→        while (i < fieldValues.size && i < n.fields.size) {
373→            if (mAllFieldsNull) {
374→                if (mCardType != null && mCardType == getString(R.string.cloze_model_name) && i == 0 ||
375→                    mCardType == getString(R.string.basic_typing_model_name) && i == 1
376→                ) {
377→                    n.setField(i, fieldValues[i])
378→                } else {
379→                    n.setField(i, "(" + fieldValues[i] + ")")
380→                }
381→            } else {
382→                n.setField(i, fieldValues[i])
383→            }
384→            i++
385→        }
386→        try {
387→            return EphemeralCard.fromNote(n, getColUnsafe, cardIndex)
388→        } catch (e: Exception) {
389→            // Calling code handles null return, so we can log this for developer's interest but move on
390→            Timber.d(e, "getDummyCard() unable to create card")
391→        }
392→        return null
393→    }
394→
395→    /** Override certain aspects of Card behavior so we may display unsaved data  */
396→    inner class PreviewerCard : Card {
397→        private val mNote: Note?
398→
399→        constructor(col: Collection, id: Long) : super(col, id) {
400→            mNote = null
401→        }
402→
403→        /* if we have an unsaved note saved, use it instead of a collection lookup */ override fun note(
404→            reload: Boolean
405→        ): Note {
406→            return mNote ?: super.note(reload)
407→        }
408→
409→        /** if we have an unsaved note saved, use it instead of a collection lookup  */
410→        override fun note(): Note {
411→            return mNote ?: super.note()
412→        }
413→
414→        /** if we have an unsaved note, never return empty  */
415→        val isEmpty: Boolean
416→            get() = mNote != null
417→
418→        /** Override the method that fetches the model so we can render unsaved models  */
419→        override fun model(): NotetypeJson {
420→            return mEditedNotetype ?: super.model()
421→        }
422→
423→        override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
424→            if (renderOutput == null || reload) {
425→                val index = if (model().isCloze) {
426→                    0
427→                } else {
428→                    ord
429→                }
430→                val context = TemplateManager.TemplateRenderContext.fromCardLayout(
431→                    note(),
432→                    this,
433→                    model(),
434→                    model().getJSONArray("tmpls")[index] as JSONObject,
435→                    fillEmpty = false
436→                )
437→                renderOutput =
438→                    context.render()
439→            }
440→            return renderOutput!!
441→        }
442→    }
443→}
444→
445→private class EphemeralCard(col: Collection, id: Long?) : Card(col, id) {
446→    override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
447→        return this.renderOutput!!
448→    }
449→    companion object {
450→        fun fromNote(n: Note, col: Collection, cardIndex: Int = 0): EphemeralCard {
451→            val card = EphemeralCard(col, null)
452→            card.did = 1
453→            card.ord = n.cardIndexToOrd(cardIndex)
454→
455→            val nt = n.notetype
456→            val templateIdx = if (nt.type == Consts.MODEL_CLOZE) {
457→                0
458→            } else {
459→                cardIndex
460→            }
461→            val template = nt.tmpls[templateIdx] as JSONObject
462→            template.put("ord", card.ord)
463→
464→            val output = TemplateManager.TemplateRenderContext.fromCardLayout(
465→                n,
466→                card,
467→                notetype = nt,
468→                template = template,
469→                fillEmpty = false
470→            ).render()
471→            card.renderOutput = output
472→            card.setNote(n)
473→            return card
474→        }
475→    }
476→}
477→
478→/** returns the number of cards from a note which has not had data saved in the database */
479→private fun Note.numberOfCardsEphemeral(): Int {
480→    // We can't use note.numberOfCards() as this uses the database value
481→    return when {
482→        this.notetype.isCloze -> col.clozeNumbersInNote(this).size.coerceAtLeast(1)
483→        else -> notetype.templatesNames.size
484→    }
485→}
486→
487→/**
488→ * Given a card index, returns the 'ord' of the card
489→ */
490→private fun Note.cardIndexToOrd(index: Int): Int {
491→    // We can't use note.numberOfCards() as this uses the database value
492→    return when {
493→        this.notetype.isCloze -> {
494→            val clozeNumbers = col.clozeNumbersInNote(this)
495→            if (clozeNumbers.isEmpty()) {
496→                0
497→            } else {
498→                clozeNumbers[index] - 1
499→            }
500→        }
501→        else -> index
502→    }
503→}
