562→        @KotlinCleanup("helper function for min/max range")
563→        cardsListView.setOnItemLongClickListener { _: AdapterView<*>?, view: View?, position: Int, _: Long ->
564→            if (isInMultiSelectMode) {
565→                var hasChanged = false
566→                for (i in min(mLastSelectedPosition, position)..max(
