 38→/**
 39→ * The previewer intent must supply an array of cards to show and the index in the list from where
 40→ * to begin showing them. Special rules are applied if the list size is 1 (i.e., no scrolling
 41→ * buttons will be shown).
 42→ */
 43→
 44→class Previewer : AbstractFlashcardViewer() {
 45→    private lateinit var mCardList: LongArray
 46→    private var mIndex = 0
 47→    private var mShowingAnswer = false
 48→    private lateinit var mProgressSeekBar: SeekBar
 49→    private lateinit var mProgressText: TextView
 50→
 51→    /** Communication with Browser  */
 52→    private var mReloadRequired = false
 53→    private var mNoteChanged = false
 54→    private var previewLayout: PreviewLayout? = null
 55→    override fun onCreate(savedInstanceState: Bundle?) {
 56→        if (showedActivityFailedScreen(savedInstanceState)) {
 57→            return
 58→        }
 59→        super.onCreate(savedInstanceState)
 60→        mCardList = intent.getLongArrayExtra("cardList")!!
 61→        mIndex = intent.getIntExtra("index", -1)
 62→        if (savedInstanceState != null) {
 63→            mIndex = savedInstanceState.getInt("index", mIndex)
 64→            mShowingAnswer = savedInstanceState.getBoolean("showingAnswer", mShowingAnswer)
 65→            mReloadRequired = savedInstanceState.getBoolean("reloadRequired")
 66→            mNoteChanged = savedInstanceState.getBoolean("noteChanged")
 67→        }
 68→        if (mCardList.isEmpty() || mIndex < 0 || mIndex > mCardList.size - 1) {
 69→            Timber.e("Previewer started with empty card list or invalid index")
 70→            finish()
 71→            return
 72→        }
 73→        showBackIcon()
 74→        // Ensure navigation drawer can't be opened. Various actions in the drawer cause crashes.
 75→        disableDrawerSwipe()
 76→        startLoadingCollection()
 77→        initPreviewProgress()
 78→        setOkResult()
 79→    }
 80→
 81→    private fun initPreviewProgress() {
 82→        mProgressSeekBar = findViewById(R.id.preview_progress_seek_bar)
 83→        mProgressText = findViewById(R.id.preview_progress_text)
 84→        val progressLayout = findViewById<LinearLayout>(R.id.preview_progress_layout)
 85→
 86→        // Show layout only when the cardList is bigger than 1
 87→        if (mCardList.size > 1) {
 88→            progressLayout.visibility = View.VISIBLE
 89→            mProgressSeekBar.max = mCardList.size - 1
 90→            setSeekBarListener()
 91→            updateProgress()
 92→        }
 93→    }
 94→
 95→    private fun setSeekBarListener() {
 96→        mProgressSeekBar.setOnSeekBarChangeListener(object : OnSeekBarChangeListener {
 97→            override fun onProgressChanged(seekBar: SeekBar, progress: Int, fromUser: Boolean) {
 98→                if (fromUser) {
 99→                    mIndex = progress
100→                    updateProgress()
101→                    currentCard = getColUnsafe.getCard(mCardList[mIndex])
102→                    displayCardQuestion()
103→                }
104→            }
105→
106→            override fun onStartTrackingTouch(seekBar: SeekBar) {
107→                // Mandatory override, but unused
108→            }
109→
110→            override fun onStopTrackingTouch(seekBar: SeekBar) {
111→                if (mIndex >= 0 && mIndex < mCardList.size) {
112→                    currentCard = getColUnsafe.getCard(mCardList[mIndex])
113→                    displayCardQuestion()
114→                }
115→            }
116→        })
117→    }
118→
119→    override fun onCollectionLoaded(col: Collection) {
120→        super.onCollectionLoaded(col)
121→        currentCard = col.getCard(mCardList[mIndex])
122→        displayCardQuestion()
123→        if (mShowingAnswer) {
124→            displayCardAnswer()
125→        }
126→        showBackIcon()
127→    }
128→
129→    /** Given a new collection of card Ids, find the 'best' valid card given the current collection
130→     * We define the best as searching to the left, then searching to the right of the current element
131→     * This occurs as many cards can be deleted when editing a note (from the Card Template Editor)  */
132→    private fun getNextIndex(newCardList: List<Long>): Int {
133→        val validIndices = HashSet(newCardList)
134→        for (i in mIndex downTo 0) {
135→            if (validIndices.contains(mCardList[i])) {
136→                return newCardList.indexOf(mCardList[i])
137→            }
138→        }
139→        for (i in mIndex + 1 until validIndices.size) {
140→            if (validIndices.contains(mCardList[i])) {
141→                return newCardList.indexOf(mCardList[i])
142→            }
143→        }
144→        throw IllegalStateException("newCardList was empty")
145→    }
146→
147→    override fun initLayout() {
148→        super.initLayout()
149→        topBarLayout!!.visibility = View.GONE
150→        findViewById<View>(R.id.answer_options_layout).visibility = View.GONE
151→        findViewById<View>(R.id.bottom_area_layout).visibility = View.VISIBLE
152→        previewLayout = PreviewLayout.createAndDisplay(this, mToggleAnswerHandler)
153→        previewLayout!!.setOnNextCard { changePreviewedCard(true) }
154→        previewLayout!!.setOnPreviousCard { changePreviewedCard(false) }
155→    }
156→
157→    override fun onOptionsItemSelected(item: MenuItem): Boolean {
158→        if (item.itemId == R.id.action_edit) {
159→            editCard()
160→            return true
161→        }
162→        return super.onOptionsItemSelected(item)
163→    }
164→
165→    override fun onNavigationPressed() {
166→        setOkResult()
167→        super.onNavigationPressed()
168→    }
169→
170→    override fun onCreateOptionsMenu(menu: Menu): Boolean {
171→        menuInflater.inflate(R.menu.previewer, menu)
172→        return super.onCreateOptionsMenu(menu)
173→    }
174→
175→    override fun onSaveInstanceState(outState: Bundle) {
176→        outState.putLongArray("cardList", mCardList)
177→        outState.putInt("index", mIndex)
178→        outState.putBoolean("showingAnswer", mShowingAnswer)
179→        outState.putBoolean("reloadRequired", mReloadRequired)
180→        outState.putBoolean("noteChanged", mNoteChanged)
181→        super.onSaveInstanceState(outState)
182→    }
183→
184→    override fun displayCardQuestion() {
185→        super.displayCardQuestion()
186→        mShowingAnswer = false
187→        updateButtonsState()
188→    }
189→
190→    // Called via mFlipCardListener in parent class when answer button pressed
191→    @VisibleForTesting(otherwise = VisibleForTesting.PROTECTED)
192→    override fun displayCardAnswer() {
193→        super.displayCardAnswer()
194→        mShowingAnswer = true
195→        updateButtonsState()
196→    }
197→
198→    override fun hideEaseButtons() {
199→        /* do nothing */
200→    }
201→
202→    override fun displayAnswerBottomBar() {
203→        /* do nothing */
204→    }
205→
206→    override fun executeCommand(which: ViewerCommand, fromGesture: Gesture?): Boolean {
207→        /* do nothing */
208→        return false
209→    }
210→
211→    override fun performReload() {
212→        mReloadRequired = true
213→        setOkResult()
214→        val newCardList = getColUnsafe.filterToValidCards(mCardList)
215→        if (newCardList.isEmpty()) {
216→            finish()
217→            return
218→        }
219→        mIndex = getNextIndex(newCardList)
220→        mCardList = newCardList.toLongArray()
221→        currentCard = getColUnsafe.getCard(mCardList[mIndex])
222→        displayCardQuestion()
223→    }
224→
225→    override fun onEditedNoteChanged() {
226→        super.onEditedNoteChanged()
227→        mNoteChanged = true
228→        setOkResult()
229→    }
230→
231→    @VisibleForTesting(otherwise = VisibleForTesting.PRIVATE)
232→    internal fun changePreviewedCard(nextCard: Boolean) {
233→        mIndex = if (nextCard) mIndex + 1 else mIndex - 1
234→        currentCard = getColUnsafe.getCard(mCardList[mIndex])
235→        displayCardQuestion()
236→        updateProgress()
237→    }
238→
239→    private val mToggleAnswerHandler = View.OnClickListener {
240→        if (mShowingAnswer) {
241→            displayCardQuestion()
242→        } else {
243→            displayCardAnswer()
244→        }
245→    }
246→
247→    private fun updateButtonsState() {
248→        previewLayout!!.setShowingAnswer(mShowingAnswer)
249→
250→        // If we are in single-card mode, we show the "Show Answer" button on the question side
251→        // and hide navigation buttons.
252→        if (mCardList.size == 1) {
253→            previewLayout!!.hideNavigationButtons()
254→            return
255→        }
256→        previewLayout!!.setPrevButtonEnabled(mIndex > 0)
257→        previewLayout!!.setNextButtonEnabled(mIndex < mCardList.size - 1)
258→    }
259→
260→    private fun updateProgress() {
261→        if (mProgressSeekBar.progress != mIndex) {
262→            mProgressSeekBar.progress = mIndex
263→        }
264→        val progress = getString(R.string.preview_progress_bar_text, mIndex + 1, mCardList.size)
265→        mProgressText.text = progress
266→    }
267→
268→    private fun setOkResult() {
269→        setResult(
270→            RESULT_OK,
271→            Intent().apply {
272→                putExtra("reloadRequired", mReloadRequired)
273→                putExtra("noteChanged", mNoteChanged)
274→            }
275→        )
276→    }
277→
278→    companion object {
279→        @CheckResult
280→        fun getPreviewIntent(context: Context?, index: Int, cardList: LongArray?): Intent {
281→            val intent = Intent(context, Previewer::class.java)
282→            intent.putExtra("index", index)
283→            intent.putExtra("cardList", cardList)
284→            return intent
285→        }
286→    }
287→}
