255→                currentCard = getDummyCard(mEditedNotetype!!, mOrdinal)
256→                if (currentCard == null) {
257→                    showThemedToast(applicationContext, getString(R.string.invalid_template), false)
258→                    closeCardTemplatePreviewer()
259→                }
260→            }
261→        }
262→        if (currentCard == null) {
263→            showThemedToast(applicationContext, getString(R.string.invalid_template), false)
264→            closeCardTemplatePreviewer()
265→            return
266→        }
267→        displayCardQuestion()
268→        if (mShowingAnswer) {
269→            displayCardAnswer()
270→        }
271→        showBackIcon()
272→    }
