312→    private fun getLabels(fieldValues: MutableList<String>) {
313→        if (mCardType != null && mCardType == getString(R.string.cloze_model_name)) {
314→            fieldValues[0] = getString(R.string.cloze_sample_text, "c1")
315→        }
316→        if (mCardType != null && mCardType == getString(R.string.basic_typing_model_name)) {
317→            fieldValues[1] = getString(R.string.basic_answer_sample_text)
318→        }
319→    }
