321→    private fun getBundleEditFields(noteEditorBundle: Bundle?): MutableList<String> {
322→        val noteFields = noteEditorBundle!!.getBundle("editFields")
323→            ?: return mutableListOf()
324→        // we map from "int" -> field, but the order isn't guaranteed, and there may be skips.
325→        // so convert this to a list of strings, with null in place of the invalid fields
326→        val elementCount = noteFields.keySet().stream().map { s: String -> s.toInt() }.max { obj: Int, anotherInteger: Int? -> obj.compareTo(anotherInteger!!) }.orElse(-1) + 1
327→        val ret = Array(elementCount) { "" } // init array, nulls cause a crash
328→        for (fieldOrd in noteFields.keySet()) {
329→            ret[fieldOrd.toInt()] = noteFields.getString(fieldOrd)!!
330→        }
331→        return mutableListOf(*ret)
332→    }
